import React from 'react';
import { QA_CATEGORIES } from './data/qa-data';

export default function KnowledgeTagsBottomInvestorCompany() {
    // Category display names mapping
    const CATEGORY_DISPLAY = {
        'SAFE': 'SAFE',
        'Convertible Debt': 'Convertible Debt',
        'Preferred Equity': 'Preferred Equity',
        'Common Equity': 'Common Equity',
        'Warrants': 'Warrants',
        'Instrument Comparisons': 'Instrument Comparisons',
        'Investor Reporting': 'Investor Reporting',
        'Data Room & Due Diligence': 'Data Room & Due Diligence',
        'Dilution & Ownership Modeling': 'Dilution',
        'Fundraising Rounds & Process': 'Fundraising',
        'Valuation Fundamentals': 'Valuation',
        'Vesting & Equity Compensation': 'Vesting',
        'Governance & Shareholder Rights': 'Governance',
        'M&A, Exits & Liquidity': 'M&A & Exit',
        'Angel Investing Fundamentals': 'Angel Investing',
        'Founder-Investor Relationships': 'Founder-Investor Relationships',
        'Term Sheet Structure and Fundamentals': 'Term Sheets'
    };

    const handleTagClick = (cat) => {
        window.dispatchEvent(new CustomEvent('openCategoryModal', { detail: cat }));
    };

    return (
        <>
            {QA_CATEGORIES.map((cat, index) => (
                <div key={index} className="knowledge__tag" onClick={() => handleTagClick(cat)}>
                    {CATEGORY_DISPLAY[cat.name] || cat.name}
                </div>
            ))}

        </>
    );
}
